                            {{ form_errors(formulaire.couleur) }}
                        </div>
                    </div>

              

                    <div class=\"d-flex justify-content-end gap-2\">
                        <a href=\"{{ path('app_tag_recette') }}\" class=\"btn btn-light px-4\">Annuler</a>

                    </div>
                {{ form_end(formulaire) }}
            </div>
        </div>
    </div>
</div>
</div>
    </div>
</div>
{% endblock %}", "tag_recette/nouvelle.html.twig", "/home/useradm/projet-recettes/templates/tag_recette/nouvelle.html.twig");
